INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", 0, "", 21, "", 0, "vo_minigame_1013", 6, "", 6005, "vo_minigame_1013_top_talk_6_000");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 1, 0, 11, 0.3, 8, 129811, 6, 0, 6006, "あたしも教官の仕事を\n頑張れば、あいつに\n喜んでもらえたり\nするのかな…");
