INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", 0, "", 21, "", 0, "vo_minigame_1013", 6, "", 6010, "vo_minigame_1013_top_talk_6_001");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 1, 0, 11, 0.8, 6, 129911, 6, 0, 6011, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", "", "", 91, "", "", 0, 6, "", 6012, "");
