INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (1, "drama_talk_surprise_loop_shy", "", 3, "", 0, 129811, 6, 0.2, 6014, "drama_talk_surprise_in_shy");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", 0, "", 21, "", 0, "vo_minigame_1013", 6, "", 6015, "vo_minigame_1013_top_talk_6_002");
