INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", 0, "", 21, "", 0, "vo_minigame_1013", 7, "", 7005, "vo_minigame_1013_top_talk_7_000");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 1, 0, 11, 0.3, 6, 129911, 7, 0, 7006, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", "", "", 91, "", "", 0, 7, "", 7007, "");
