INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", 0, "", 21, "", 0, "vo_minigame_1013", 7, "", 7015, "vo_minigame_1013_top_talk_7_002");
